SELECT p."name" AS product_name, AVG(pl."qty") AS average_units_picked FROM "ORACLE_SQL"."ORACLE_SQL"."PICKING_LINE" pl JOIN "ORACLE_SQL"."ORACLE_SQL"."PRODUCTS" p ON pl."product_id" = p."id" JOIN "ORACLE_SQL"."ORACLE_SQL"."PICKING_LOG" log ON pl."picklist_id" = log."picklist_id" AND pl."line_no" = log."pickline_no" WHERE pl."order_id" = 421 AND log."activity" = 'P' GROUP BY p."id", p."name" ORDER BY p."name"